// Copyright (c) HashiCorp, Inc.
// SPDX-License-Identifier: BUSL-1.1

package format

import (
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter produces a condensed, summary-style diff output for a
// terraform plan, showing only resource-level changes without attribute-level
// detail. Changes are grouped by action type and a count summary is appended.
type CompactDiffFormatter struct{}

// Format renders a compact, human-readable summary of all resource instance
// changes in the given plan. Each resource is listed on one line with its
// action keyword, grouped by action type. A summary line is included at the
// end showing total counts per action.
//
// The schemas parameter is accepted for API compatibility but is not required
// for compact output, which operates solely on action metadata.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return "No changes. Infrastructure is up-to-date."
	}

	// Collect resource changes grouped by canonical action label.
	type entry struct {
		label string
		addr  string
	}

	// actionOrder defines the display order for action groups.
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.CreateThenForget,
		plans.Forget,
		plans.Read,
	}

	actionLabel := map[plans.Action]string{
		plans.Create:           "create",
		plans.Update:           "update",
		plans.Delete:           "delete",
		plans.DeleteThenCreate: "replace",
		plans.CreateThenDelete: "replace",
		plans.CreateThenForget: "replace",
		plans.Forget:           "remove",
		plans.Read:             "read",
	}

	// grouped maps each action to the sorted list of resource addresses.
	grouped := make(map[plans.Action][]string)

	for _, rc := range plan.Changes.Resources {
		action := rc.Action
		if action == plans.NoOp {
			continue
		}
		grouped[action] = append(grouped[action], rc.Addr.String())
	}

	// Sort addresses within each group for stable output.
	for action := range grouped {
		sort.Strings(grouped[action])
	}

	var buf strings.Builder

	hasChanges := false
	for _, action := range actionOrder {
		addrs, ok := grouped[action]
		if !ok {
			continue
		}
		hasChanges = true
		label := actionLabel[action]
		for _, addr := range addrs {
			fmt.Fprintf(&buf, "%s: %s\n", label, addr)
		}
	}

	if !hasChanges {
		return "No changes. Infrastructure is up-to-date."
	}

	// Build summary counts. "replace" actions are counted separately from
	// create/update/delete for clarity.
	counts := map[string]int{}
	for action, addrs := range grouped {
		label := actionLabel[action]
		counts[label] += len(addrs)
	}

	buf.WriteString("\n")
	buf.WriteString(formatSummary(counts))

	return buf.String()
}

// formatSummary returns the "Plan: N to create, N to update, N to destroy."
// summary line from a map of action-label → count.
func formatSummary(counts map[string]int) string {
	var parts []string

	add := func(label, singular, plural string) {
		n, ok := counts[label]
		if !ok || n == 0 {
			return
		}
		noun := plural
		if n == 1 {
			noun = singular
		}
		parts = append(parts, fmt.Sprintf("%d %s", n, noun))
	}

	add("create", "to create", "to create")
	add("update", "to update", "to update")
	add("delete", "to destroy", "to destroy")
	add("replace", "to replace", "to replace")
	add("remove", "to remove", "to remove")
	add("read", "to read", "to read")

	if len(parts) == 0 {
		return "No changes."
	}
	return "Plan: " + strings.Join(parts, ", ") + "."
}

