// Copyright (c) HashiCorp, Inc.
// SPDX-License-Identifier: BUSL-1.1

package format

import (
	"strings"
	"testing"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
)

// mustAbsResourceInstance is a helper that builds an AbsResourceInstance for
// managed resources in the root module without instance keys.
func mustAbsResourceInstance(resourceType, name string) addrs.AbsResourceInstance {
	return addrs.AbsResourceInstance{
		Module: addrs.RootModuleInstance,
		Resource: addrs.ResourceInstance{
			Resource: addrs.Resource{
				Mode: addrs.ManagedResourceMode,
				Type: resourceType,
				Name: name,
			},
			Key: addrs.NoKey,
		},
	}
}

// makeResourceChangeSrc builds a minimal ResourceInstanceChangeSrc for testing.
func makeResourceChangeSrc(addr addrs.AbsResourceInstance, action plans.Action) *plans.ResourceInstanceChangeSrc {
	return &plans.ResourceInstanceChangeSrc{
		Addr:        addr,
		PrevRunAddr: addr,
		ChangeSrc: plans.ChangeSrc{
			Action: action,
		},
	}
}

func TestCompactDiffFormatter_NilPlan(t *testing.T) {
	f := &CompactDiffFormatter{}
	got := f.Format(nil, nil)
	if !strings.Contains(got, "No changes") {
		t.Errorf("expected 'No changes' message for nil plan, got: %q", got)
	}
}

func TestCompactDiffFormatter_EmptyChanges(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)
	if !strings.Contains(got, "No changes") {
		t.Errorf("expected 'No changes' message for empty plan, got: %q", got)
	}
}

func TestCompactDiffFormatter_NoOpSkipped(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "noop"), plans.NoOp),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)
	if !strings.Contains(got, "No changes") {
		t.Errorf("expected 'No changes' when only NoOp changes present, got: %q", got)
	}
}

func TestCompactDiffFormatter_SingleCreate(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "web"), plans.Create),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "create: aws_instance.web") {
		t.Errorf("expected create line in output, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to create") {
		t.Errorf("expected summary '1 to create', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_SingleUpdate(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_security_group", "allow_ssh"), plans.Update),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "update: aws_security_group.allow_ssh") {
		t.Errorf("expected update line in output, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to update") {
		t.Errorf("expected summary '1 to update', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_SingleDelete(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_elb", "frontend"), plans.Delete),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "delete: aws_elb.frontend") {
		t.Errorf("expected delete line in output, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to destroy") {
		t.Errorf("expected summary '1 to destroy', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_ReplaceDeleteThenCreate(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_launch_configuration", "as_conf"), plans.DeleteThenCreate),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "replace: aws_launch_configuration.as_conf") {
		t.Errorf("expected replace line in output, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to replace") {
		t.Errorf("expected summary '1 to replace', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_ReplaceCreateThenDelete(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "blue"), plans.CreateThenDelete),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "replace: aws_instance.blue") {
		t.Errorf("expected replace line in output, got:\n%s", got)
	}
}

func TestCompactDiffFormatter_MixedActions(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "web"), plans.Create),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_security_group", "allow_ssh"), plans.Update),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_elb", "frontend"), plans.Delete),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_launch_configuration", "as_conf"), plans.DeleteThenCreate),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_s3_bucket", "noop_bucket"), plans.NoOp),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	checks := []string{
		"create: aws_instance.web",
		"update: aws_security_group.allow_ssh",
		"delete: aws_elb.frontend",
		"replace: aws_launch_configuration.as_conf",
		"1 to create",
		"1 to update",
		"1 to destroy",
		"1 to replace",
	}
	for _, want := range checks {
		if !strings.Contains(got, want) {
			t.Errorf("expected %q in output, got:\n%s", want, got)
		}
	}

	// NoOp resources must not appear in the output.
	if strings.Contains(got, "aws_s3_bucket.noop_bucket") {
		t.Errorf("NoOp resource should not appear in compact output, got:\n%s", got)
	}
}

func TestCompactDiffFormatter_OutputGroupedByAction(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "b"), plans.Create),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "a"), plans.Create),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_db_instance", "main"), plans.Delete),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	// Both creates should appear before the delete, and addresses within the
	// create group should be sorted alphabetically.
	createAPos := strings.Index(got, "create: aws_instance.a")
	createBPos := strings.Index(got, "create: aws_instance.b")
	deletePos := strings.Index(got, "delete: aws_db_instance.main")

	if createAPos == -1 || createBPos == -1 || deletePos == -1 {
		t.Fatalf("one or more expected lines missing from output:\n%s", got)
	}
	if createAPos > createBPos {
		t.Errorf("expected aws_instance.a before aws_instance.b (sorted), got:\n%s", got)
	}
	if createBPos > deletePos {
		t.Errorf("expected creates before deletes in output, got:\n%s", got)
	}
}

func TestCompactDiffFormatter_SummaryLine(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "one"), plans.Create),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "two"), plans.Create),
		makeResourceChangeSrc(mustAbsResourceInstance("aws_db_instance", "db"), plans.Update),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "2 to create") {
		t.Errorf("expected '2 to create' in summary, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to update") {
		t.Errorf("expected '1 to update' in summary, got:\n%s", got)
	}
	if !strings.HasSuffix(strings.TrimSpace(got), ".") {
		t.Errorf("expected summary line ending with '.', got:\n%s", got)
	}
}

func TestCompactDiffFormatter_ForgetAction(t *testing.T) {
	plan := &plans.Plan{
		Changes: plans.NewChangesSrc(),
	}
	plan.Changes.Resources = []*plans.ResourceInstanceChangeSrc{
		makeResourceChangeSrc(mustAbsResourceInstance("aws_instance", "legacy"), plans.Forget),
	}
	f := &CompactDiffFormatter{}
	got := f.Format(plan, nil)

	if !strings.Contains(got, "remove: aws_instance.legacy") {
		t.Errorf("expected remove line for Forget action, got:\n%s", got)
	}
	if !strings.Contains(got, "1 to remove") {
		t.Errorf("expected '1 to remove' in summary, got:\n%s", got)
	}
}

